  /* Chat bubbles */
  .chat-bubble {
    padding: 16px 24px; border-radius: 16px;
    font-size: 20px; font-weight: 500; line-height: 1.4;
    max-width: 440px; position: relative;
  }
  .chat-bubble.claude {
    background: rgba(59, 130, 246, 0.12);
    border: 1px solid rgba(59, 130, 246, 0.3);
    color: #60a5fa;
  }
  .chat-bubble.claude::before {
    content: 'CLAUDE'; display: block;
    font-size: 15px; font-weight: 700; letter-spacing: 1px;
    margin-bottom: 6px; color: var(--accent-blue);
  }
  .chat-bubble.claude::after {
    content: '';
    position: absolute; left: -12px; top: 28px;
    width: 0; height: 0;
    border-top: 8px solid transparent;
    border-bottom: 8px solid transparent;
    border-right: 12px solid rgba(59, 130, 246, 0.3);
  }
  .chat-bubble.user {
    background: rgba(139, 92, 246, 0.12);
    border: 1px solid rgba(139, 92, 246, 0.3);
    color: #a78bfa;
  }
  .chat-bubble.user::before {
    content: 'YOU'; display: block;
    font-size: 15px; font-weight: 700; letter-spacing: 1px;
    margin-bottom: 6px; color: var(--accent-purple);
  }
  .chat-bubble.user::after {
    content: '';
    position: absolute; right: -12px; top: 28px;
    width: 0; height: 0;
    border-top: 8px solid transparent;
    border-bottom: 8px solid transparent;
    border-left: 12px solid rgba(139, 92, 246, 0.3);
  }

  /* Symptom block */
  .symptom-block {
    background: var(--bg-card);
    border-radius: 16px; padding: 24px 28px;
    display: flex; align-items: center; gap: 16px;
    min-width: 0;
  }

  /* Foundation slab */
  .foundation {
    background: rgba(239, 68, 68, 0.1);
    border: 2px solid rgba(239, 68, 68, 0.35);
    border-radius: 12px; padding: 24px 32px;
    display: flex; justify-content: space-between; align-items: center;
